glass main() -> Int {
  spillage {
    throw "fire";
  } cleanup (e: Error) {
    pour("rescued");
  }
  return 0;
}

glass main() -> Int {
  spillage {
    throw "x";
  } cleanup (e: Error) {
    pour("a");
  } finally {
    pour("b");
  }
  return 0;
}

glass main() -> Int {
  spillage {
    pour("try");
  } cleanup (e: Error) {
    pour("catch");
  } finally {
    pour("finally");
  }
  return 0;
}

glass main() -> Int {
  drink x: Int = 1 / 0;
  return 0;
}

glass main() -> Int {
  drink v: Any = empty;
  condense(v);
  return 0;
}

glass loop(n: Int) -> Int {
  return loop(n + 1);
}
glass main() -> Int {
  loop(0);
  return 0;
}

glass inner() -> Int {
  throw "inner";
  return 0;
}
glass main() -> Int {
  spillage {
    inner();
  } cleanup (e: Error) {
    pour("outer caught");
  }
  return 0;
}

glass main() -> Int {
  drink mut count: Int = 0;
  spillage {
    throw "a";
  } cleanup (e: Error) {
    drip count;
  }
  spillage {
    throw "b";
  } cleanup (e: Error) {
    drip count;
  }
  pour(count);
  return 0;
}

glass main() -> Int {
  drink mut log: Reservoir[String] = [];
  spillage {
    throw "x";
  } cleanup (e: Error) {
    push(log, "cleanup");
  } finally {
    push(log, "finally");
  }
  pour(get(log, 0));
  pour(get(log, 1));
  return 0;
}
